#!/usr/bin/env bash
# Downloads Stitch htmlCode and screenshot URLs into html/ and screenshots/
set -euo pipefail
ROOT="$(cd "$(dirname "$0")" && pwd)"
HTML="$ROOT/html"
IMG="$ROOT/screenshots"
mkdir -p "$HTML" "$IMG"

slugify() {
  echo "$1" | tr '[:upper:]' '[:lower:]' | sed -E 's/[^a-z0-9]+/-/g; s/^-|-$//g'
}

download() {
  local url="$1" out="$2"
  if [[ -f "$out" && -s "$out" ]]; then
    echo "skip exists $out"
    return
  fi
  echo "GET $out"
  curl -sS -L -f "$url" -o "$out" || { echo "FAILED $url" >&2; return 1; }
}

# title|screenId|htmlUrl|screenshotUrl (optional)
while IFS='|' read -r title sid htmlUrl shotUrl; do
  base="$(slugify "$title")-${sid:0:8}"
  download "$htmlUrl" "$HTML/${base}.html"
  if [[ -n "$shotUrl" ]]; then
    # Stitch screenshot URLs are often extensionless; always use .jpg for googleusercontent raster links.
    download "$shotUrl" "$IMG/${base}.jpg"
  fi
done <<'ROWS'
